<?php
namespace Tests\Unit\Domain\WorldMaps;use App\Domain\WorldMaps\WorldMapPolygonValidator;use InvalidArgumentException;use Tests\TestCase;
class WorldMapPolygonValidatorTest extends TestCase{private function validator(){return new WorldMapPolygonValidator();}public function test_normalizes_precision_and_preserves_order(){$p=$this->validator()->normalize(['coordinate_system'=>'normalized','points'=>[['x'=>0.123456789,'y'=>0.1],['x'=>0.8,'y'=>0.1],['x'=>0.4,'y'=>0.8]]]);$this->assertSame(0.123457,$p['points'][0]['x']);$this->assertSame(0.8,$p['points'][1]['x']);}public function test_rejects_invalid_geometry(){foreach([[['x'=>0,'y'=>0],['x'=>1,'y'=>0]],[['x'=>0,'y'=>0],['x'=>1.1,'y'=>0],['x'=>0,'y'=>1]],[['x'=>0,'y'=>0],['x'=>1,'y'=>1],['x'=>0,'y'=>1],['x'=>1,'y'=>0]],[['x'=>0,'y'=>0],['x'=>1,'y'=>0],['x'=>1,'y'=>0]]] as $points){try{$this->validator()->normalize(['coordinate_system'=>'normalized','points'=>$points]);$this->fail('Expected invalid polygon.');}catch(InvalidArgumentException $e){$this->assertTrue(true);}}}public function test_separate_polygons_may_overlap(){$a=$this->validator()->normalize(['coordinate_system'=>'normalized','points'=>[['x'=>0,'y'=>0],['x'=>0.8,'y'=>0],['x'=>0,'y'=>0.8]]]);$b=$this->validator()->normalize(['coordinate_system'=>'normalized','points'=>[['x'=>0.1,'y'=>0.1],['x'=>0.9,'y'=>0.1],['x'=>0.1,'y'=>0.9]]]);$this->assertNotEmpty($a);$this->assertNotEmpty($b);}}
